# ============================================================================# GitLab 性能优化配置 - 专用于 CI/CD 场景# ============================================================================# 配置访问地址external_url 'http://192.168.235.127:80'# ----------------------------------------------------------------------------# 禁用监控相关服务（不需要内置监控）# ----------------------------------------------------------------------------alertmanager['enable'] = falseprometheus['enable'] = falsenode_exporter['enable'] = falseredis_exporter['enable'] = falsepostgres_exporter['enable'] = falsegitlab_rails['exporter_enabled'] = falsepuma['exporter_enabled'] = false# ----------------------------------------------------------------------------# 禁用不需要的集成功能# ----------------------------------------------------------------------------# Kubernetes 集成gitlab_kas['enable'] = false# Pages 静态网站托管gitlab_pages['enable'] = false# Container Registry 容器镜像仓库registry['enable'] = falsegitlab_rails['registry_enabled'] = false# Mattermost 团队协作mattermost['enable'] = false# Geo 地理分布式geo_postgresql['enable'] = falsegeo_logcursor['enable'] = false# Spamcheck 垃圾邮件检查spamcheck['enable'] = false# Service Desk 服务台gitlab_rails['service_desk_email_enabled'] = false# ----------------------------------------------------------------------------# 禁用外部服务和遥测# ----------------------------------------------------------------------------# LDAP 认证（如不需要）gitlab_rails['ldap_enabled'] = false# OmniAuth 第三方登录（如只需要本地账号）gitlab_rails['omniauth_enabled'] = false# Gravatar 头像（内网环境）gitlab_rails['gravatar_plain_url'] = ''gitlab_rails['gravatar_ssl_url'] = ''# 使用统计上报gitlab_rails['usage_ping_enabled'] = true# Sentry 错误报告gitlab_rails['sentry_enabled'] = falsegitlab_pages['sentry_enabled'] = false# Feature Flags（GitLab内部用）gitlab_rails['feature_flags_unleash_enabled'] = false# ----------------------------------------------------------------------------# 基础配置# ----------------------------------------------------------------------------gitlab_rails['time_zone'] = 'Asia/Shanghai'# ----------------------------------------------------------------------------# Nginx 优化（CI/CD 大文件传输）# ----------------------------------------------------------------------------nginx['enable'] = truenginx['client_max_body_size'] = '512m'nginx['gzip_enabled'] = truenginx['worker_processes'] = 4nginx['worker_connections'] = 10240# ----------------------------------------------------------------------------# Sidekiq 优化（根据服务器配置调整）# ----------------------------------------------------------------------------sidekiq['concurrency'] = 20# ----------------------------------------------------------------------------# 限流优化配置（CI/CD 场景不限流）# ----------------------------------------------------------------------------# 设置为服务器 CPU 核心数puma['worker_processes'] = 4puma['max_threads'] = 4puma['min_threads'] = 2# Web 请求超时优化nginx['proxy_read_timeout'] = 3600nginx['proxy_connect_timeout'] = 300# Git HTTP/SSH 操作不限流gitlab_rails['gitlab_shell_git_timeout'] = 800# LFS 大文件存储gitlab_rails['lfs_enabled'] = true# Webhook 不限流gitlab_rails['webhook_timeout'] = 300# 增加工作进程队列容量gitlab_workhorse['api_limit'] = 0gitlab_workhorse['api_queue_limit'] = 0gitlab_workhorse['api_ci_long_polling_duration'] = '300s'# Redis 连接数优化redis['maxclients'] = '20000'